def check_fat_over_105g(product):
    """
    Returns the tag "fat-value-over-105g" if the product's 'fat' field exceeds 105.
    Returns None if the field is missing, non-numeric, or does not exceed the threshold.
    """
    tag = "fat-value-over-105g"
    value = product.get("fat")
    if value is None:
        return None
    try:
        numeric_value = float(value)
    except (TypeError, ValueError):
        return None
    if numeric_value > 105:
        return tag
    return None

